import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { propertiesData, getFilterOptions, filterProperties } from '../data/propertiesData';
import { Home, Building2, Filter, X } from 'lucide-react';

const Projects = () => {
  const navigate = useNavigate();
  const [filters, setFilters] = useState({
    category: 'All',
    listingType: 'All',
    propertyType: 'All',
    maxPrice: 50000000
  });
  const [showMobileFilters, setShowMobileFilters] = useState(false);
  const [priceRangeType, setPriceRangeType] = useState('lakhs');
  
  const filterOptions = getFilterOptions();
  const filteredProperties = filterProperties(propertiesData, filters);
  
  const getCurrentPropertyTypes = () => {
    if (filters.category === 'Residential') return filterOptions.propertyTypes.Residential;
    if (filters.category === 'Commercial') return filterOptions.propertyTypes.Commercial;
    return ['All'];
  };
  
  const formatPrice = (price, listingType) => {
    if (listingType === 'Rent') {
      if (price >= 100000) return `₹${(price / 100000).toFixed(1)}L/month`;
      return `₹${price.toLocaleString('en-IN')}/month`;
    }
    if (listingType === 'Lease') {
      if (price >= 100000) return `₹${(price / 100000).toFixed(1)}L/year`;
      return `₹${price.toLocaleString('en-IN')}/year`;
    }
    if (price >= 10000000) return `₹${(price / 10000000).toFixed(2)} Cr`;
    if (price >= 100000) return `₹${(price / 100000).toFixed(1)} Lakhs`;
    return `₹${price.toLocaleString('en-IN')}`;
  };
  
  const getListingTypeColor = (type) => {
    switch(type) {
      case 'Sale': return 'bg-green-500';
      case 'Rent': return 'bg-blue-500';
      case 'Lease': return 'bg-purple-500';
      default: return 'bg-gray-500';
    }
  };
  
  const getCategoryIcon = (category) => {
    return category === 'Residential' ? <Home size={14} /> : <Building2 size={14} />;
  };

  const handleViewDetails = (propertyId) => {
    navigate(`/property/${propertyId}`);
  };

  // Convert slider value to actual price based on selected type
  const getSliderValue = () => {
    if (priceRangeType === 'thousands') return filters.maxPrice / 1000;
    if (priceRangeType === 'lakhs') return filters.maxPrice / 100000;
    return filters.maxPrice / 10000000; // crores
  };

  const handlePriceChange = (sliderValue) => {
    let actualPrice;
    if (priceRangeType === 'thousands') actualPrice = sliderValue * 1000;
    else if (priceRangeType === 'lakhs') actualPrice = sliderValue * 100000;
    else actualPrice = sliderValue * 10000000;
    setFilters({...filters, maxPrice: actualPrice});
  };

  // Get slider max based on type
  const getSliderMax = () => {
    if (priceRangeType === 'thousands') return 50000; // 5 Crore in thousands
    if (priceRangeType === 'lakhs') return 500; // 5 Crore in lakhs
    return 5; // 5 Crore
  };

  const getSliderStep = () => {
    if (priceRangeType === 'thousands') return 5; // ₹5,000 steps
    if (priceRangeType === 'lakhs') return 1; // ₹1 Lakh steps
    return 0.1; // ₹10 Lakh steps
  };

  const formatDisplayPrice = (price) => {
    if (price >= 10000000) return `₹${(price / 10000000).toFixed(2)} Cr`;
    if (price >= 100000) return `₹${(price / 100000).toFixed(1)} L`;
    if (price >= 1000) return `₹${(price / 1000).toFixed(0)}K`;
    return `₹${price}`;
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="pt-28 pb-16 bg-gray-50 min-h-screen"
    >
      <div className="container-custom">
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold text-[#0a192f] mb-3">Find Your Dream Property</h1>
          <p className="text-gray-600 text-lg">Discover residential & commercial properties in Nashik</p>
        </div>
        
        <div className="lg:hidden mb-4">
          <button
            onClick={() => setShowMobileFilters(!showMobileFilters)}
            className="w-full bg-white border-2 border-[#d4af37] rounded-lg py-3 flex items-center justify-center gap-2 font-semibold"
          >
            <Filter size={18} /> {showMobileFilters ? 'Hide Filters' : 'Show Filters'}
          </button>
        </div>
        
        <div className={`bg-white rounded-xl shadow-md p-5 mb-8 ${showMobileFilters ? 'block' : 'hidden lg:block'}`}>
          <div className="flex flex-wrap items-end gap-4">
            <div className="flex-1 min-w-[140px]">
              <label className="block text-xs text-gray-500 mb-1 font-semibold">Category</label>
              <select
                value={filters.category}
                onChange={(e) => setFilters({...filters, category: e.target.value, propertyType: 'All'})}
                className="w-full p-2.5 border rounded-lg text-sm bg-gray-50"
              >
                {filterOptions.categories.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>
            
            <div className="flex-1 min-w-[120px]">
              <label className="block text-xs text-gray-500 mb-1 font-semibold">Listing Type</label>
              <select
                value={filters.listingType}
                onChange={(e) => setFilters({...filters, listingType: e.target.value})}
                className="w-full p-2.5 border rounded-lg text-sm bg-gray-50"
              >
                {filterOptions.listingTypes.map(type => (
                  <option key={type} value={type}>{type}</option>
                ))}
              </select>
            </div>
            
            {(filters.category === 'Residential' || filters.category === 'Commercial') && (
              <div className="flex-1 min-w-[140px]">
                <label className="block text-xs text-gray-500 mb-1 font-semibold">Property Type</label>
                <select
                  value={filters.propertyType}
                  onChange={(e) => setFilters({...filters, propertyType: e.target.value})}
                  className="w-full p-2.5 border rounded-lg text-sm bg-gray-50"
                >
                  {getCurrentPropertyTypes().map(type => (
                    <option key={type} value={type}>{type}</option>
                  ))}
                </select>
              </div>
            )}
            
            <div className="flex-1 min-w-[280px]">
              <label className="block text-xs text-gray-500 mb-1 font-semibold">Max Price</label>
              <div className="flex gap-2">
                <select
                  value={priceRangeType}
                  onChange={(e) => setPriceRangeType(e.target.value)}
                  className="p-2 border rounded-lg text-sm bg-gray-50 w-28"
                >
                  <option value="thousands">₹ Thousands</option>
                  <option value="lakhs">₹ Lakhs</option>
                  <option value="crores">₹ Crores</option>
                </select>
                <div className="flex-1">
                  <input
                    type="range"
                    min={priceRangeType === 'thousands' ? 5 : priceRangeType === 'lakhs' ? 1 : 0.1}
                    max={getSliderMax()}
                    step={getSliderStep()}
                    value={getSliderValue()}
                    onChange={(e) => handlePriceChange(parseFloat(e.target.value))}
                    className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-[#d4af37]"
                  />
                </div>
              </div>
              <div className="text-right mt-1">
                <span className="text-sm font-bold text-[#d4af37]">
                  Up to {formatDisplayPrice(filters.maxPrice)}
                </span>
              </div>
            </div>
            
            <button
              onClick={() => setFilters({ category: 'All', listingType: 'All', propertyType: 'All', maxPrice: 50000000 })}
              className="px-5 py-2.5 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition flex items-center gap-1"
            >
              <X size={16} /> Reset
            </button>
          </div>
        </div>
        
        <div className="mb-6">
          <p className="text-gray-500">
            <span className="font-bold text-[#d4af37] text-lg">{filteredProperties.length}</span> properties found
          </p>
        </div>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredProperties.map((property, index) => (
            <motion.div
              key={property.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.05 }}
              className="bg-white rounded-xl shadow-lg overflow-hidden hover:shadow-2xl transition-all duration-300 hover:-translate-y-2 cursor-pointer"
              onClick={() => handleViewDetails(property.id)}
            >
              <div className="relative h-52 overflow-hidden bg-gray-200">
                <img 
                  src={property.images[0]} 
                  alt={property.title}
                  className="w-full h-full object-cover transition-transform duration-500 hover:scale-110"
                  onError={(e) => {
                    e.target.src = 'https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?w=800';
                  }}
                />
                <div className="absolute top-3 left-3 flex gap-2">
                  <span className={`${getListingTypeColor(property.listingType)} text-white px-2 py-1 rounded-lg text-xs font-semibold flex items-center gap-1`}>
                    {getCategoryIcon(property.category)}
                    {property.listingType}
                  </span>
                </div>
                <div className="absolute top-3 right-3">
                  <span className="bg-[#d4af37] text-[#0a192f] px-2 py-1 rounded-lg text-xs font-semibold">
                    {property.propertyType}
                  </span>
                </div>
              </div>
              
              <div className="p-4">
                <h3 className="text-lg font-bold text-[#0a192f] mb-1">{property.title}</h3>
                <p className="text-gray-500 text-sm mb-2">📍 {property.location}</p>
                <p className="text-[#d4af37] font-bold text-xl">
                  {formatPrice(property.price, property.listingType)}
                </p>
                
                <div className="flex gap-4 mt-3 text-sm text-gray-500">
                  {property.bedrooms > 0 && <span>🛏️ {property.bedrooms} BHK</span>}
                  <span>📐 {property.area_sqft} sq.ft</span>
                </div>
                
                <button 
                  className="w-full mt-4 bg-[#d4af37] text-[#0a192f] py-2.5 rounded-lg font-semibold hover:bg-opacity-90 transition"
                  onClick={(e) => {
                    e.stopPropagation();
                    handleViewDetails(property.id);
                  }}
                >
                  View Details →
                </button>
              </div>
            </motion.div>
          ))}
        </div>
        
        {filteredProperties.length === 0 && (
          <div className="text-center py-16 bg-white rounded-xl">
            <p className="text-gray-500 text-lg">No properties match your filters.</p>
            <button
              onClick={() => setFilters({ category: 'All', listingType: 'All', propertyType: 'All', maxPrice: 50000000 })}
              className="mt-4 text-[#d4af37] hover:underline font-semibold"
            >
              Clear all filters
            </button>
          </div>
        )}
      </div>
    </motion.div>
  );
};

export default Projects;
